const body = $input.first().json.body || $input.first().json;
const cookies = body.cookies || {};
const cookieEntries = Object.entries(cookies);
const cookieString = cookieEntries.map(([k, v]) => `${k}=${v}`).join('; ');

return [
  {
    json: {
      cookieString,
      telegram_user_id: body.telegram_user_id,
      hasCookies: cookieEntries.length > 0
    }
  }
];

const html = $input.first().json.data || $input.first().json.body || '';

function extractAll(regex, text) {
  const matches = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    matches.push(match);
  }
  return matches;
}

const courses = [];
const rowRegex = /<tr[^>]*>.*?<\/tr>/gs;
const rows = extractAll(rowRegex, html);

for (const rowMatch of rows) {
  const row = rowMatch[0];
  const cellRegex = /<td[^>]*>(.*?)<\/td>/gs;
  const cells = extractAll(cellRegex, row);

  if (cells.length >= 3) {
    const getText = (htmlStr) => htmlStr.replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').trim();
    const texts = cells.map(c => getText(c[1]));

    if (texts[0] && texts[0].length > 0 && !texts[0].toLowerCase().includes('no')) {
      const matkul = texts[1] || texts[0];
      const kelas = texts[2] || 'N/A';
      const sks = texts[3] || 'N/A';

      if (matkul && matkul.length > 2) {
        courses.push({
          matkul,
          id: texts[0] || 'N/A',
          sks,
          kelas,
          ruang: texts[4] || 'N/A',
          jadwal: texts[5] || 'N/A',
          pengampu: texts[6] || 'N/A'
        });
      }
    }
  }
}

if (courses.length === 0) {
  const cardRegex = /<div[^>]*class=["'][^"']*kelas[^"']*["'][^>]*>(.*?)<\/div>/gs;
  const cards = extractAll(cardRegex, html);

  for (let i = 0; i < cards.length; i++) {
    const card = cards[i][1];
    const text = card.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    if (text.length > 3) {
      courses.push({
        matkul: text,
        id: String(i + 1),
        sks: 'N/A',
        kelas: 'N/A',
        ruang: 'N/A',
        jadwal: 'N/A',
        pengampu: 'N/A'
      });
    }
  }
}

return [
  {
    json: {
      matakuliah: courses,
      count: courses.length,
      success: courses.length > 0
    }
  }
];
